/* tokens/fonts.css is generated by scripts/fetch-fonts.mjs and is not one of
 * the four files check-tokens-generated.mjs guards, so nothing noticed when
 * the two drifted. Editing font.display and not re-running the generator used
 * to resolve to a family with no @font-face and fall through to system-ui
 * with no error at all -- the worst shape a broken promise can take.
 *
 * For every family declared in tokens/src/typography.json's `font` group —
 * the first entry of each $value array, since the rest are generic
 * fallbacks (`system-ui`, `sans-serif`, `monospace`…) and were never meant
 * to carry a face — this asserts tokens/fonts.css has at least one matching
 * @font-face. families() (scripts/fetch-fonts.mjs) is the single reader of
 * that first-entry rule, so this gate and the generator can never disagree
 * about which name is "the family" versus "a fallback".
 *
 *   bun scripts/check-fonts-generated.mjs   -> exit 0 if every family has a face
 */
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { families } from './fetch-fonts.mjs';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');

/** @param {string} css @returns {Set<string>} every font-family named inside
 *  an @font-face block — single- or double-quoted, exactly as fetch-fonts.mjs
 *  writes it. */
export function facesIn(css) {
  const faces = new Set();
  const re = /@font-face\s*{([^}]*)}/g;
  let m;
  while ((m = re.exec(css)) !== null) {
    const fam = /font-family:\s*['"]([^'"]+)['"]/.exec(m[1]);
    if (fam) faces.add(fam[1]);
  }
  return faces;
}

/** @param {string[]} declared — the first $value entry of every `font.*`
 *  token, in declaration order.
 *  @param {Set<string>} faces — every family named by an @font-face in
 *  tokens/fonts.css.
 *  @returns {string[]} one message per declared family with no matching
 *  face, naming the family and pointing at the fix. Empty when every
 *  declared family has one. */
export function checkFonts(declared, faces) {
  return declared
    .filter((fam) => !faces.has(fam))
    .map((fam) => `"${fam}" is declared in tokens/src/typography.json but tokens/fonts.css has no @font-face for it — run bun scripts/fetch-fonts.mjs`);
}

function main() {
  const declared = families(root).map((f) => f.css);
  const css = readFileSync(join(root, 'tokens', 'fonts.css'), 'utf8');
  const errs = checkFonts(declared, facesIn(css));

  if (errs.length) {
    console.error(`check-fonts-generated: ${errs.length} declared famil${errs.length === 1 ? 'y' : 'ies'} with no @font-face\n`);
    for (const e of errs) console.error(`  ${e}`);
    process.exit(1);
  }
  console.log(`check-fonts-generated: ${declared.length} famil${declared.length === 1 ? 'y' : 'ies'} declared, every one has a face in tokens/fonts.css`);
}

if (process.argv[1] === fileURLToPath(import.meta.url)) main();
